function cherryPickup(grid) {
    let rows = grid.length;
    let cols = grid[0].length;
    let dp = new Array(rows).fill(0).map(() => new Array(cols).fill(0).map(() => new Array(cols).fill(0)));

    for (let row = rows - 1; row >= 0; --row) {
        for (let col1 = 0; col1 < cols; ++col1) {
            for (let col2 = 0; col2 < cols; ++col2) {
                let currentCell = row < rows - 1 ? dp[row + 1][col1][col2] : 0;
                currentCell += grid[row][col1] + (col1 !== col2 ? grid[row][col2] : 0);

                let maxVal = 0;
                for (let move1 = -1; move1 <= 1; ++move1) {
                    for (let move2 = -1; move2 <= 1; ++move2) {
                        let newCol1 = col1 + move1;
                        let newCol2 = col2 + move2;
                        if (newCol1 >= 0 && newCol1 < cols && newCol2 >= 0 && newCol2 < cols) {
                            maxVal = Math.max(maxVal, dp[row][newCol1][newCol2]);
                        }
                    }
                }

                dp[row][col1][col2] = currentCell + maxVal;
            }
        }
    }

    return dp[0][0][cols - 1];
}
```


    We use a 3D dynamic programming approach where dp[row][col1][col2] - cherries count that can be picked by two robots by the end of row 'row' if the first robot is currently in the cell (row, col1) and the second robot is currently in the cell (row, col2)

1. Iterate through the rows in reverse order, from the bottom to the top.
2. For each row, iterate through the columns col1 and col2 for the first and second robot and calculate the cherries collected in the current cell.
3. Calculate the maximum number of cherries that can be collected for the current cell by accounting for valid moves in the next row.
4. Update dp[row][col1][col2] with the sum of cherries collected at the current cell and maximum cherries that can be collected in the next row.
5. Return dp[0][0][cols-1] which represents the maximum number of cherries that can be collected by both robots after reaching the top row.

